code.C:
#include <stdio.h>

int main() {
    int t, x, y, z;
    scanf("%d", &t);

    while (t--) {
        scanf("%d %d %d", &x, &y, &z);

        if (x > (y > z ? y : z)) {
            printf("Setter\n");
        } else if (y > (x > z ? x : z)) {
            printf("Tester\n");
        } else {
            printf("Editorialist\n");
        }
    }

    return 0;
}

