code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let input = [];
rl.on('line', (line) => {
    input.push(line.trim());
});

rl.on('close', () => {
    let t = parseInt(input[0]);
    for (let i = 1; i <= t; i++) {
        let [x, y, z] = input[i].split(' ').map(Number);
        if (x > Math.max(y, z)) {
            console.log("Setter");
        } else if (y > Math.max(x, z)) {
            console.log("Tester");
        } else {
            console.log("Editorialist");
        }
    }
});

